// Domain types shared between the main process and renderer.
// All datetimes are ISO 8601 strings (SQLite has no native datetime).

export type RecurringPattern = 'none' | 'daily' | 'weekly' | 'monthly'

export interface Category {
  id: number
  name: string
  color: string // hex e.g. "#6366f1"
  sortOrder: number
  createdAt: string
}

export interface CategoryWithCount extends Category {
  taskCount: number
}

export interface Task {
  id: number
  categoryId: number | null
  title: string
  color: string | null // per-task color override
  dueDate: string | null // ISO date e.g. "2024-03-15"
  dueBefore5pm: boolean
  timeEstimateMins: number | null
  sortOrder: number
  isComplete: boolean
  completedAt: string | null
  recurringPattern: RecurringPattern
  recurringBaseId: number | null
  xpValue: number
  createdAt: string
  updatedAt: string
}

export interface Subtask {
  id: number
  taskId: number
  title: string
  isComplete: boolean
  sortOrder: number
  createdAt: string
}

export interface PomodoroSession {
  id: number
  taskId: number | null
  phase: 'work' | 'short_break' | 'long_break'
  durationS: number
  startedAt: string
  completedAt: string | null
  wasCompleted: boolean
}

export interface UserStats {
  totalXp: number
  level: number
  updatedAt: string
}

export interface GamificationStats extends UserStats {
  todayPomodoros: number
}

/** Returned by tasks:complete — includes XP awarded and updated stats. */
export interface CompleteTaskResult {
  task: Task
  xpGained: number
  stats: GamificationStats
}

// IPC payload types

export type CreateTaskPayload = Omit<Task, 'id' | 'createdAt' | 'updatedAt' | 'completedAt'>
export type UpdateTaskPayload = { id: number } & Partial<Omit<Task, 'id' | 'createdAt'>>

export type CreateCategoryPayload = { name: string; color: string }
export type UpdateCategoryPayload = { id: number; name?: string; color?: string }

export type CreateSubtaskPayload = { taskId: number; title: string }
export type UpdateSubtaskPayload = { id: number; title?: string; isComplete?: boolean }

import { useState } from 'react'
import type { Task, CategoryWithCount, CreateTaskPayload, UpdateTaskPayload, CompleteTaskResult } from '@shared/types'
import { TaskCard } from './TaskCard'
import { TaskForm } from './TaskForm'
import { useAppStore } from '@renderer/store/appStore'
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragEndEvent
} from '@dnd-kit/core'
import {
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy
} from '@dnd-kit/sortable'
import { Plus } from 'lucide-react'

interface TaskListProps {
  tasks: Task[]
  categories: CategoryWithCount[]
  onAddTask: (payload: CreateTaskPayload) => Promise<void>
  onEditTask: (payload: UpdateTaskPayload) => Promise<void>
  onDeleteTask: (id: number) => Promise<void>
  onCompleteTask: (id: number) => Promise<CompleteTaskResult>
  onReorder: (oldIndex: number, newIndex: number) => Promise<void>
}

export function TaskList({
  tasks,
  categories,
  onAddTask,
  onEditTask,
  onDeleteTask,
  onCompleteTask,
  onReorder
}: TaskListProps) {
  const { activeCategoryId } = useAppStore()
  const [showForm, setShowForm] = useState(false)

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates
    })
  )

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event
    if (!over || active.id === over.id) return

    const oldIndex = tasks.findIndex((t) => t.id === active.id)
    const newIndex = tasks.findIndex((t) => t.id === over.id)
    if (oldIndex !== -1 && newIndex !== -1) {
      onReorder(oldIndex, newIndex)
    }
  }

  return (
    <div className="flex flex-col h-full">
      {/* Add task button */}
      <div className="flex-shrink-0 px-4 pt-4 pb-2">
        <button
          onClick={() => setShowForm(true)}
          className="flex items-center gap-2 w-full px-4 py-2.5 rounded-md border border-dashed border-border text-sm text-muted-foreground hover:text-foreground hover:border-border/80 hover:bg-accent/30 transition-colors"
        >
          <Plus className="h-4 w-4" />
          Add task
        </button>
      </div>

      {/* Sortable task list */}
      <div className="flex-1 overflow-y-auto px-4 pb-4 space-y-2">
        {tasks.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-muted-foreground">
            <p className="text-sm">No tasks yet.</p>
            <p className="text-xs mt-1">Add one above or use Brain Dump (Ctrl+Space).</p>
          </div>
        ) : (
          <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
            <SortableContext items={tasks.map((t) => t.id)} strategy={verticalListSortingStrategy}>
              {tasks.map((task) => (
                <TaskCard
                  key={task.id}
                  task={task}
                  categories={categories}
                  onComplete={onCompleteTask}
                  onEdit={onEditTask}
                  onDelete={onDeleteTask}
                />
              ))}
            </SortableContext>
          </DndContext>
        )}
      </div>

      {showForm && (
        <TaskForm
          categories={categories}
          defaultCategoryId={activeCategoryId}
          onSave={onAddTask}
          onClose={() => setShowForm(false)}
        />
      )}
    </div>
  )
}

import { useEffect, useCallback } from 'react'
import { Sidebar } from '@renderer/components/layout/Sidebar'
import { Header } from '@renderer/components/layout/Header'
import { Before5pmBanner } from '@renderer/components/banner/Before5pmBanner'
import { BrainDumpInput } from '@renderer/components/braindump/BrainDumpInput'
import { TaskList } from '@renderer/components/tasks/TaskList'
import { FocusMode } from '@renderer/components/focus/FocusMode'
import { GamificationStub } from '@renderer/components/gamification/GamificationStub'
import { useAppStore } from '@renderer/store/appStore'
import { useCategories } from '@renderer/hooks/useCategories'
import { useTasks } from '@renderer/hooks/useTasks'
import { useUserStats } from '@renderer/hooks/useUserStats'

export function App() {
  const { activeCategoryId, focusMode, exitFocusMode } = useAppStore()

  const { categories, refresh: refreshCategories, addCategory, editCategory, removeCategory } =
    useCategories()

  const {
    tasks,
    refresh: refreshTasks,
    addTask,
    editTask,
    removeTask,
    reorder,
    markComplete
  } = useTasks({ categoryId: activeCategoryId ?? undefined })

  const { stats: gamificationStats, onTaskComplete } = useUserStats()

  // Load initial data
  useEffect(() => {
    refreshCategories()
    refreshTasks()
  }, [])

  // Re-fetch tasks when active category changes
  useEffect(() => {
    refreshTasks()
  }, [activeCategoryId])

  // Also refresh categories (for task counts) after task mutations
  const handleAddTask = useCallback(
    async (payload: Parameters<typeof addTask>[0]) => {
      await addTask(payload)
      await refreshCategories()
    },
    [addTask, refreshCategories]
  )

  const handleCompleteTask = useCallback(
    async (id: number) => {
      const result = await markComplete(id)
      onTaskComplete(result)
      await refreshCategories()
    },
    [markComplete, refreshCategories, onTaskComplete]
  )

  const handleDeleteTask = useCallback(
    async (id: number) => {
      await removeTask(id)
      await refreshCategories()
    },
    [removeTask, refreshCategories]
  )

  // Escape exits focus mode
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && focusMode) exitFocusMode()
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [focusMode, exitFocusMode])

  const totalTaskCount = categories.reduce((sum, c) => sum + c.taskCount, 0)

  return (
    <div className="flex h-full bg-background">
      {/* Always-visible sidebar */}
      <Sidebar
        categories={categories}
        totalTaskCount={totalTaskCount}
        gamificationStats={gamificationStats}
        onAddCategory={addCategory}
        onEditCategory={editCategory}
        onDeleteCategory={removeCategory}
      />

      {/* Main area */}
      <div className="flex-1 flex flex-col min-w-0">
        <Header />

        {/* Before 5PM banner — appears automatically when relevant tasks exist */}
        <Before5pmBanner tasks={tasks} />

        {/* Brain dump quick-add strip */}
        <BrainDumpInput categories={categories} onAdd={handleAddTask} />

        {/* Task list */}
        <div className="flex-1 overflow-hidden">
          <TaskList
            tasks={tasks}
            categories={categories}
            onAddTask={handleAddTask}
            onEditTask={editTask}
            onDeleteTask={handleDeleteTask}
            onCompleteTask={handleCompleteTask}
            onReorder={reorder}
          />
        </div>
      </div>

      {/* Focus mode overlay — renders on top of everything */}
      <FocusMode tasks={tasks} categories={categories} />

      {/* Gamification placeholder */}
      <GamificationStub />
    </div>
  )
}

import type { GamificationStats } from '@shared/types'

interface XpBarProps {
  stats: GamificationStats & { xpGained: number }
}

// XP needed within the current level (always 100 per level in this formula)
const XP_PER_LEVEL = 100

export function XpBar({ stats }: XpBarProps) {
  const { totalXp, level, todayPomodoros, xpGained } = stats

  // How far through the current level (0–99)
  const xpInLevel = totalXp % XP_PER_LEVEL
  const fillPct = (xpInLevel / XP_PER_LEVEL) * 100

  return (
    <div className="relative px-3 py-2.5 border-b border-border">
      {/* Level + XP row */}
      <div className="flex items-center justify-between mb-1.5">
        <span className="text-[11px] font-bold text-primary tracking-wide">Lv. {level}</span>
        <span className="text-[10px] text-muted-foreground font-mono">
          {xpInLevel} / {XP_PER_LEVEL} XP
        </span>
      </div>

      {/* XP progress bar */}
      <div className="h-1.5 bg-muted rounded-full overflow-hidden">
        <div
          className="h-full bg-primary rounded-full transition-all duration-700 ease-out"
          style={{ width: `${fillPct}%` }}
        />
      </div>

      {/* Pomodoro today counter */}
      <div className="flex items-center gap-1 mt-2">
        <span className="text-sm leading-none">🍅</span>
        <span className="text-[10px] text-muted-foreground">
          {todayPomodoros} focus session{todayPomodoros !== 1 ? 's' : ''} today
        </span>
      </div>

      {/* Floating "+XP" animation — appears above bar when xpGained > 0 */}
      {xpGained > 0 && (
        <div
          key={totalXp} // re-mount on each new gain so the animation restarts
          className="absolute right-3 top-1 text-xs font-bold text-primary animate-xp-float pointer-events-none"
        >
          +{xpGained} XP
        </div>
      )}
    </div>
  )
}

import { useState } from 'react'
import type { CategoryWithCount, CreateCategoryPayload, UpdateCategoryPayload, GamificationStats } from '@shared/types'
import { CategoryItem } from '@renderer/components/categories/CategoryItem'
import { CategoryForm } from '@renderer/components/categories/CategoryForm'
import { XpBar } from '@renderer/components/gamification/XpBar'
import { useAppStore } from '@renderer/store/appStore'
import { Plus, LayoutList } from 'lucide-react'
import { cn } from '@renderer/lib/utils'

interface SidebarProps {
  categories: CategoryWithCount[]
  totalTaskCount: number
  gamificationStats: GamificationStats & { xpGained: number }
  onAddCategory: (payload: CreateCategoryPayload) => Promise<void>
  onEditCategory: (payload: UpdateCategoryPayload) => Promise<void>
  onDeleteCategory: (id: number) => Promise<void>
}

export function Sidebar({
  categories,
  totalTaskCount,
  gamificationStats,
  onAddCategory,
  onEditCategory,
  onDeleteCategory
}: SidebarProps) {
  const { activeCategoryId, setActiveCategoryId } = useAppStore()
  const [showAddForm, setShowAddForm] = useState(false)

  return (
    <aside className="w-56 flex-shrink-0 bg-card border-r border-border flex flex-col h-full">
      <div className="px-3 py-4 border-b border-border">
        <h1 className="text-sm font-bold text-foreground tracking-wider uppercase">ADHD Todo</h1>
      </div>

      {/* XP / level bar — always visible */}
      <XpBar stats={gamificationStats} />

      <nav className="flex-1 overflow-y-auto px-2 py-3 space-y-0.5">
        {/* "All Tasks" entry — always at top */}
        <div
          className={cn(
            'flex items-center gap-2 px-3 py-2 rounded-md cursor-pointer transition-colors',
            activeCategoryId === null
              ? 'bg-accent text-foreground'
              : 'text-muted-foreground hover:bg-accent/50 hover:text-foreground'
          )}
          onClick={() => setActiveCategoryId(null)}
        >
          <LayoutList className="h-3.5 w-3.5 flex-shrink-0" />
          <span className="flex-1 text-sm">All Tasks</span>
          {totalTaskCount > 0 && (
            <span className="text-xs bg-muted text-muted-foreground rounded-full px-1.5 py-0.5 font-mono">
              {totalTaskCount}
            </span>
          )}
        </div>

        {/* Category list — always fully visible (never collapsed) */}
        <div className="pt-2">
          <p className="px-3 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground mb-1">
            Categories
          </p>
          {categories.map((cat) => (
            <CategoryItem
              key={cat.id}
              category={cat}
              isActive={activeCategoryId === cat.id}
              onSelect={() => setActiveCategoryId(cat.id)}
              onEdit={onEditCategory}
              onDelete={onDeleteCategory}
            />
          ))}
        </div>
      </nav>

      {/* Add category button — always visible at bottom */}
      <div className="px-2 py-3 border-t border-border">
        <button
          onClick={() => setShowAddForm(true)}
          className="flex items-center gap-2 w-full px-3 py-2 rounded-md text-sm text-muted-foreground hover:text-foreground hover:bg-accent/50 transition-colors"
        >
          <Plus className="h-3.5 w-3.5" />
          Add category
        </button>
      </div>

      {showAddForm && (
        <CategoryForm onSave={onAddCategory} onClose={() => setShowAddForm(false)} />
      )}
    </aside>
  )
}

import { useState } from 'react'
import type { Task, CategoryWithCount, UpdateTaskPayload } from '@shared/types'
import { SubtaskList } from './SubtaskList'
import { TaskForm } from './TaskForm'
import { RecurringBadge } from './RecurringBadge'
import { useSortable } from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import { format, isToday, isPast, parseISO } from 'date-fns'
import { formatMinutes } from '@renderer/lib/utils'
import { useAppStore } from '@renderer/store/appStore'
import {
  CheckSquare,
  Square,
  ChevronDown,
  ChevronRight,
  GripVertical,
  Pencil,
  Trash2,
  Focus,
  Clock,
  AlertCircle
} from 'lucide-react'
import { cn } from '@renderer/lib/utils'
import type { CompleteTaskResult } from '@shared/types'

interface TaskCardProps {
  task: Task
  categories: CategoryWithCount[]
  onComplete: (id: number) => Promise<CompleteTaskResult>
  onEdit: (payload: UpdateTaskPayload) => Promise<void>
  onDelete: (id: number) => Promise<void>
}

export function TaskCard({ task, categories, onComplete, onEdit, onDelete }: TaskCardProps) {
  const [expanded, setExpanded] = useState(false)
  const [showForm, setShowForm] = useState(false)
  const [completing, setCompleting] = useState(false)
  const { enterFocusMode } = useAppStore()

  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: task.id
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.4 : 1
  }

  // Determine due date display color
  const dueDateEl = (() => {
    if (!task.dueDate) return null
    const d = parseISO(task.dueDate)
    const isOverdue = isPast(d) && !isToday(d)
    const label = isToday(d) ? 'Today' : format(d, 'MMM d')
    return (
      <span
        className={cn(
          'inline-flex items-center gap-1 text-[10px] px-1.5 py-0.5 rounded',
          isOverdue
            ? 'bg-red-950 text-red-400'
            : isToday(d)
              ? 'bg-amber-950 text-amber-400'
              : 'bg-muted text-muted-foreground'
        )}
      >
        {isOverdue && <AlertCircle className="h-2.5 w-2.5" />}
        {label}
      </span>
    )
  })()

  const category = categories.find((c) => c.id === task.categoryId)
  const cardColor = task.color ?? category?.color

  return (
    <>
      <div
        ref={setNodeRef}
        style={style}
        className={cn(
          'group relative bg-card border border-border rounded-md overflow-hidden transition-shadow hover:shadow-md',
          isDragging && 'shadow-lg',
          completing && 'animate-task-complete pointer-events-none'
        )}
      >
        {/* Left color bar */}
        {cardColor && (
          <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: cardColor }} />
        )}

        <div className={cn('flex items-start gap-2 px-3 py-2.5', cardColor && 'pl-4')}>
          {/* Drag handle */}
          <div
            {...attributes}
            {...listeners}
            className="flex-shrink-0 mt-0.5 text-muted-foreground hover:text-foreground cursor-grab active:cursor-grabbing touch-none"
          >
            <GripVertical className="h-4 w-4" />
          </div>

          {/* Complete checkbox — triggers animation then removes card */}
          <button
            onClick={async () => {
              if (completing) return
              setCompleting(true)
              // Let the animation play before the card is removed from the list
              await new Promise((r) => setTimeout(r, 500))
              await onComplete(task.id)
            }}
            className="flex-shrink-0 mt-0.5 text-muted-foreground hover:text-primary transition-colors"
          >
            {completing ? (
              <CheckSquare className="h-4 w-4 text-primary" />
            ) : (
              <Square className="h-4 w-4" />
            )}
          </button>

          {/* Main content */}
          <div className="flex-1 min-w-0">
            <div className="flex items-start gap-2">
              <span className="flex-1 text-sm text-foreground leading-tight break-words">
                {task.title}
              </span>
              {task.dueBefore5pm && (
                <span className="flex-shrink-0 text-[10px] font-bold text-amber-400 bg-amber-950 px-1.5 py-0.5 rounded">
                  ≤5PM
                </span>
              )}
            </div>

            {/* Metadata row */}
            <div className="flex items-center gap-2 mt-1 flex-wrap">
              {dueDateEl}
              {task.timeEstimateMins != null && (
                <span className="inline-flex items-center gap-1 text-[10px] text-muted-foreground">
                  <Clock className="h-2.5 w-2.5" />
                  {formatMinutes(task.timeEstimateMins)}
                </span>
              )}
              <RecurringBadge pattern={task.recurringPattern} />
              {category && (
                <span className="inline-flex items-center gap-1 text-[10px] text-muted-foreground">
                  <span
                    className="w-2 h-2 rounded-full"
                    style={{ backgroundColor: category.color }}
                  />
                  {category.name}
                </span>
              )}
            </div>

            {/* Subtask list (expanded) */}
            {expanded && <SubtaskList taskId={task.id} />}
          </div>

          {/* Right-side action buttons */}
          <div className="flex-shrink-0 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
            <button
              onClick={() => setExpanded((v) => !v)}
              title="Toggle subtasks"
              className="p-1 rounded text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
            >
              {expanded ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />}
            </button>
            <button
              onClick={() => enterFocusMode(task.id)}
              title="Focus on this task"
              className="p-1 rounded text-muted-foreground hover:text-primary hover:bg-muted transition-colors"
            >
              <Focus className="h-3.5 w-3.5" />
            </button>
            <button
              onClick={() => setShowForm(true)}
              title="Edit task"
              className="p-1 rounded text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
            >
              <Pencil className="h-3.5 w-3.5" />
            </button>
            <button
              onClick={() => onDelete(task.id)}
              title="Delete task"
              className="p-1 rounded text-muted-foreground hover:text-destructive hover:bg-muted transition-colors"
            >
              <Trash2 className="h-3.5 w-3.5" />
            </button>
          </div>
        </div>
      </div>

      {showForm && (
        <TaskForm
          initial={task}
          categories={categories}
          onSave={onEdit}
          onClose={() => setShowForm(false)}
        />
      )}
    </>
  )
}

import type Database from 'better-sqlite3'

/** Run once on startup. CREATE TABLE IF NOT EXISTS is idempotent. */
export function runMigrations(db: Database.Database): void {
  db.pragma('journal_mode = WAL')
  db.pragma('foreign_keys = ON')

  db.exec(`
    CREATE TABLE IF NOT EXISTS categories (
      id         INTEGER PRIMARY KEY AUTOINCREMENT,
      name       TEXT    NOT NULL UNIQUE,
      color      TEXT    NOT NULL DEFAULT '#6366f1',
      sort_order INTEGER NOT NULL DEFAULT 0,
      created_at TEXT    NOT NULL DEFAULT (datetime('now'))
    );

    INSERT OR IGNORE INTO categories (name, color, sort_order)
    VALUES ('Inbox', '#6366f1', 0);

    CREATE TABLE IF NOT EXISTS tasks (
      id                  INTEGER PRIMARY KEY AUTOINCREMENT,
      category_id         INTEGER REFERENCES categories(id) ON DELETE SET NULL,
      title               TEXT    NOT NULL,
      color               TEXT,
      due_date            TEXT,
      due_before_5pm      INTEGER NOT NULL DEFAULT 0,
      time_estimate_mins  INTEGER,
      sort_order          INTEGER NOT NULL DEFAULT 0,
      is_complete         INTEGER NOT NULL DEFAULT 0,
      completed_at        TEXT,
      recurring_pattern   TEXT    NOT NULL DEFAULT 'none',
      recurring_base_id   INTEGER REFERENCES tasks(id) ON DELETE SET NULL,
      created_at          TEXT    NOT NULL DEFAULT (datetime('now')),
      updated_at          TEXT    NOT NULL DEFAULT (datetime('now'))
    );

    CREATE INDEX IF NOT EXISTS idx_tasks_category ON tasks(category_id);
    CREATE INDEX IF NOT EXISTS idx_tasks_due_date  ON tasks(due_date);
    CREATE INDEX IF NOT EXISTS idx_tasks_complete  ON tasks(is_complete);

    CREATE TABLE IF NOT EXISTS subtasks (
      id          INTEGER PRIMARY KEY AUTOINCREMENT,
      task_id     INTEGER NOT NULL REFERENCES tasks(id) ON DELETE CASCADE,
      title       TEXT    NOT NULL,
      is_complete INTEGER NOT NULL DEFAULT 0,
      sort_order  INTEGER NOT NULL DEFAULT 0,
      created_at  TEXT    NOT NULL DEFAULT (datetime('now'))
    );

    CREATE INDEX IF NOT EXISTS idx_subtasks_task ON subtasks(task_id);

    CREATE TABLE IF NOT EXISTS pomodoro_sessions (
      id           INTEGER PRIMARY KEY AUTOINCREMENT,
      task_id      INTEGER REFERENCES tasks(id) ON DELETE SET NULL,
      phase        TEXT    NOT NULL,
      duration_s   INTEGER NOT NULL,
      started_at   TEXT    NOT NULL DEFAULT (datetime('now')),
      completed_at TEXT,
      was_completed INTEGER NOT NULL DEFAULT 0
    );

    CREATE INDEX IF NOT EXISTS idx_pomodoro_task    ON pomodoro_sessions(task_id);
    CREATE INDEX IF NOT EXISTS idx_pomodoro_started ON pomodoro_sessions(started_at);

    CREATE TABLE IF NOT EXISTS user_stats (
      id         INTEGER PRIMARY KEY,
      total_xp   INTEGER NOT NULL DEFAULT 0,
      level      INTEGER NOT NULL DEFAULT 1,
      updated_at TEXT    NOT NULL DEFAULT (datetime('now'))
    );
    INSERT OR IGNORE INTO user_stats (id, total_xp, level) VALUES (1, 0, 1);
  `)

  // ALTER TABLE doesn't support IF NOT EXISTS — wrap in try/catch so re-runs are safe
  try {
    db.exec(`ALTER TABLE tasks ADD COLUMN xp_value INTEGER NOT NULL DEFAULT 10`)
  } catch {
    // Column already exists — ignore
  }
}

import type Database from 'better-sqlite3'
import { addDays, addWeeks, addMonths, format } from 'date-fns'
import type { Task, CreateTaskPayload, UpdateTaskPayload } from '@shared/types'

function rowToTask(row: Record<string, unknown>): Task {
  return {
    id: row.id as number,
    categoryId: row.category_id as number | null,
    title: row.title as string,
    color: row.color as string | null,
    dueDate: row.due_date as string | null,
    dueBefore5pm: Boolean(row.due_before_5pm),
    timeEstimateMins: row.time_estimate_mins as number | null,
    sortOrder: row.sort_order as number,
    isComplete: Boolean(row.is_complete),
    completedAt: row.completed_at as string | null,
    recurringPattern: (row.recurring_pattern as Task['recurringPattern']) ?? 'none',
    recurringBaseId: row.recurring_base_id as number | null,
    xpValue: (row.xp_value as number) ?? 10,
    createdAt: row.created_at as string,
    updatedAt: row.updated_at as string
  }
}

export function getAllTasks(
  db: Database.Database,
  opts: { categoryId?: number; includeComplete?: boolean } = {}
): Task[] {
  const conditions: string[] = []
  const params: unknown[] = []

  if (!opts.includeComplete) {
    conditions.push('is_complete = 0')
  }
  if (opts.categoryId !== undefined) {
    conditions.push('category_id = ?')
    params.push(opts.categoryId)
  }

  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : ''
  const rows = db
    .prepare(`SELECT * FROM tasks ${where} ORDER BY sort_order ASC, created_at ASC`)
    .all(...params) as Record<string, unknown>[]

  return rows.map(rowToTask)
}

export function getTaskById(db: Database.Database, id: number): Task | null {
  const row = db.prepare('SELECT * FROM tasks WHERE id = ?').get(id) as
    | Record<string, unknown>
    | undefined
  return row ? rowToTask(row) : null
}

export function createTask(db: Database.Database, payload: CreateTaskPayload): Task {
  const maxOrder = (
    db.prepare('SELECT MAX(sort_order) AS m FROM tasks WHERE is_complete = 0').get() as {
      m: number | null
    }
  ).m
  const sortOrder = maxOrder != null ? maxOrder + 1 : 0

  const result = db
    .prepare(
      `INSERT INTO tasks
         (category_id, title, color, due_date, due_before_5pm, time_estimate_mins,
          sort_order, is_complete, recurring_pattern, recurring_base_id)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
    )
    .run(
      payload.categoryId ?? null,
      payload.title,
      payload.color ?? null,
      payload.dueDate ?? null,
      payload.dueBefore5pm ? 1 : 0,
      payload.timeEstimateMins ?? null,
      sortOrder,
      payload.isComplete ? 1 : 0,
      payload.recurringPattern ?? 'none',
      payload.recurringBaseId ?? null
    )

  return getTaskById(db, result.lastInsertRowid as number)!
}

export function updateTask(db: Database.Database, payload: UpdateTaskPayload): Task {
  const fields: string[] = []
  const values: unknown[] = []

  const map: Record<string, string> = {
    categoryId: 'category_id',
    title: 'title',
    color: 'color',
    dueDate: 'due_date',
    dueBefore5pm: 'due_before_5pm',
    timeEstimateMins: 'time_estimate_mins',
    sortOrder: 'sort_order',
    isComplete: 'is_complete',
    completedAt: 'completed_at',
    recurringPattern: 'recurring_pattern',
    recurringBaseId: 'recurring_base_id'
  }

  for (const [key, col] of Object.entries(map)) {
    if (key in payload && key !== 'id') {
      fields.push(`${col} = ?`)
      const val = payload[key as keyof UpdateTaskPayload]
      // Convert booleans to 0/1 for SQLite
      values.push(typeof val === 'boolean' ? (val ? 1 : 0) : val)
    }
  }

  if (fields.length > 0) {
    fields.push("updated_at = datetime('now')")
    values.push(payload.id)
    db.prepare(`UPDATE tasks SET ${fields.join(', ')} WHERE id = ?`).run(...values)
  }

  return getTaskById(db, payload.id)!
}

export function deleteTask(db: Database.Database, id: number): void {
  db.prepare('DELETE FROM tasks WHERE id = ?').run(id)
}

/** Bulk-update sort_order based on an ordered array of IDs. */
export function reorderTasks(db: Database.Database, orderedIds: number[]): void {
  const stmt = db.prepare('UPDATE tasks SET sort_order = ? WHERE id = ?')
  const bulk = db.transaction(() => {
    orderedIds.forEach((id, index) => stmt.run(index, id))
  })
  bulk()
}

/**
 * Mark a task complete. If it has a recurring pattern, generates the next occurrence.
 * Returns the updated task.
 */
export function completeTask(db: Database.Database, id: number): Task {
  const now = new Date().toISOString()
  db.prepare(
    `UPDATE tasks SET is_complete = 1, completed_at = ?, updated_at = datetime('now') WHERE id = ?`
  ).run(now, id)

  const task = getTaskById(db, id)!

  // Spawn next recurrence if applicable
  if (task.recurringPattern !== 'none' && task.dueDate) {
    const base = new Date(task.dueDate)
    let nextDate: Date
    if (task.recurringPattern === 'daily') nextDate = addDays(base, 1)
    else if (task.recurringPattern === 'weekly') nextDate = addWeeks(base, 1)
    else nextDate = addMonths(base, 1)

    createTask(db, {
      categoryId: task.categoryId,
      title: task.title,
      color: task.color,
      dueDate: format(nextDate, 'yyyy-MM-dd'),
      dueBefore5pm: task.dueBefore5pm,
      timeEstimateMins: task.timeEstimateMins,
      sortOrder: task.sortOrder,
      isComplete: false,
      recurringPattern: task.recurringPattern,
      recurringBaseId: task.recurringBaseId ?? id
    })
  }

  return task
}

import type Database from 'better-sqlite3'
import type { Subtask, CreateSubtaskPayload, UpdateSubtaskPayload } from '@shared/types'

function rowToSubtask(row: Record<string, unknown>): Subtask {
  return {
    id: row.id as number,
    taskId: row.task_id as number,
    title: row.title as string,
    isComplete: Boolean(row.is_complete),
    sortOrder: row.sort_order as number,
    createdAt: row.created_at as string
  }
}

export function getSubtasksByTask(db: Database.Database, taskId: number): Subtask[] {
  const rows = db
    .prepare('SELECT * FROM subtasks WHERE task_id = ? ORDER BY sort_order ASC, created_at ASC')
    .all(taskId) as Record<string, unknown>[]
  return rows.map(rowToSubtask)
}

export function createSubtask(db: Database.Database, payload: CreateSubtaskPayload): Subtask {
  const maxOrder = (
    db
      .prepare('SELECT MAX(sort_order) AS m FROM subtasks WHERE task_id = ?')
      .get(payload.taskId) as { m: number | null }
  ).m
  const sortOrder = maxOrder != null ? maxOrder + 1 : 0

  const result = db
    .prepare('INSERT INTO subtasks (task_id, title, sort_order) VALUES (?, ?, ?)')
    .run(payload.taskId, payload.title, sortOrder)

  const row = db
    .prepare('SELECT * FROM subtasks WHERE id = ?')
    .get(result.lastInsertRowid) as Record<string, unknown>
  return rowToSubtask(row)
}

export function updateSubtask(db: Database.Database, payload: UpdateSubtaskPayload): Subtask {
  const fields: string[] = []
  const values: unknown[] = []

  if (payload.title !== undefined) {
    fields.push('title = ?')
    values.push(payload.title)
  }
  if (payload.isComplete !== undefined) {
    fields.push('is_complete = ?')
    values.push(payload.isComplete ? 1 : 0)
  }

  if (fields.length > 0) {
    values.push(payload.id)
    db.prepare(`UPDATE subtasks SET ${fields.join(', ')} WHERE id = ?`).run(...values)
  }

  const row = db
    .prepare('SELECT * FROM subtasks WHERE id = ?')
    .get(payload.id) as Record<string, unknown>
  return rowToSubtask(row)
}

export function deleteSubtask(db: Database.Database, id: number): void {
  db.prepare('DELETE FROM subtasks WHERE id = ?').run(id)
}

export function reorderSubtasks(db: Database.Database, orderedIds: number[]): void {
  const stmt = db.prepare('UPDATE subtasks SET sort_order = ? WHERE id = ?')
  const bulk = db.transaction(() => {
    orderedIds.forEach((id, index) => stmt.run(index, id))
  })
  bulk()
}

import { useState } from 'react'
import type { Task, CategoryWithCount, CreateTaskPayload, UpdateTaskPayload, RecurringPattern } from '@shared/types'

const COLORS = [
  { label: 'Default', value: null },
  { label: 'Red', value: '#ef4444' },
  { label: 'Orange', value: '#f97316' },
  { label: 'Yellow', value: '#eab308' },
  { label: 'Green', value: '#22c55e' },
  { label: 'Blue', value: '#3b82f6' },
  { label: 'Purple', value: '#8b5cf6' },
  { label: 'Pink', value: '#ec4899' }
]

interface TaskFormProps {
  initial?: Task
  categories: CategoryWithCount[]
  defaultCategoryId?: number | null
  onSave: (payload: CreateTaskPayload | UpdateTaskPayload) => Promise<void>
  onClose: () => void
}

export function TaskForm({ initial, categories, defaultCategoryId, onSave, onClose }: TaskFormProps) {
  const [title, setTitle] = useState(initial?.title ?? '')
  const [categoryId, setCategoryId] = useState<number | null>(
    initial?.categoryId ?? defaultCategoryId ?? (categories[0]?.id ?? null)
  )
  const [color, setColor] = useState<string | null>(initial?.color ?? null)
  const [dueDate, setDueDate] = useState(initial?.dueDate ?? '')
  const [dueBefore5pm, setDueBefore5pm] = useState(initial?.dueBefore5pm ?? false)
  const [timeEstimateMins, setTimeEstimateMins] = useState<string>(
    initial?.timeEstimateMins != null ? String(initial.timeEstimateMins) : ''
  )
  const [recurringPattern, setRecurringPattern] = useState<RecurringPattern>(
    initial?.recurringPattern ?? 'none'
  )
  const [saving, setSaving] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!title.trim()) return
    setSaving(true)
    try {
      const base = {
        categoryId,
        title: title.trim(),
        color,
        dueDate: dueDate || null,
        dueBefore5pm,
        timeEstimateMins: timeEstimateMins ? parseInt(timeEstimateMins, 10) : null,
        recurringPattern,
        recurringBaseId: initial?.recurringBaseId ?? null
      }

      if (initial) {
        await onSave({ id: initial.id, ...base, isComplete: initial.isComplete })
      } else {
        await onSave({ ...base, isComplete: false, sortOrder: 0 })
      }
      onClose()
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60" onClick={onClose}>
      <form
        onSubmit={handleSubmit}
        className="bg-card border border-border rounded-lg p-5 w-[480px] shadow-xl space-y-4"
        onClick={(e) => e.stopPropagation()}
      >
        <h2 className="font-semibold text-foreground">{initial ? 'Edit Task' : 'New Task'}</h2>

        {/* Title */}
        <input
          autoFocus
          type="text"
          placeholder="What needs to be done?"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className="w-full bg-input border border-border rounded px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-1 focus:ring-ring"
        />

        <div className="grid grid-cols-2 gap-3">
          {/* Category */}
          <div>
            <label className="block text-xs text-muted-foreground mb-1">Category</label>
            <select
              value={categoryId ?? ''}
              onChange={(e) => setCategoryId(e.target.value ? Number(e.target.value) : null)}
              className="w-full bg-input border border-border rounded px-2 py-1.5 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-ring"
            >
              <option value="">None</option>
              {categories.map((c) => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>

          {/* Time estimate */}
          <div>
            <label className="block text-xs text-muted-foreground mb-1">Time estimate (min)</label>
            <input
              type="number"
              min={1}
              placeholder="e.g. 30"
              value={timeEstimateMins}
              onChange={(e) => setTimeEstimateMins(e.target.value)}
              className="w-full bg-input border border-border rounded px-3 py-1.5 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-1 focus:ring-ring"
            />
          </div>

          {/* Due date */}
          <div>
            <label className="block text-xs text-muted-foreground mb-1">Due date</label>
            <input
              type="date"
              value={dueDate}
              onChange={(e) => setDueDate(e.target.value)}
              className="w-full bg-input border border-border rounded px-3 py-1.5 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-ring [color-scheme:dark]"
            />
          </div>

          {/* Recurring */}
          <div>
            <label className="block text-xs text-muted-foreground mb-1">Repeats</label>
            <select
              value={recurringPattern}
              onChange={(e) => setRecurringPattern(e.target.value as RecurringPattern)}
              className="w-full bg-input border border-border rounded px-2 py-1.5 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-ring"
            >
              <option value="none">Never</option>
              <option value="daily">Daily</option>
              <option value="weekly">Weekly</option>
              <option value="monthly">Monthly</option>
            </select>
          </div>
        </div>

        {/* Due before 5pm */}
        <label className="flex items-center gap-2 text-sm text-foreground cursor-pointer">
          <input
            type="checkbox"
            checked={dueBefore5pm}
            onChange={(e) => setDueBefore5pm(e.target.checked)}
            className="accent-primary"
          />
          Mark as "Do Before 5 PM"
        </label>

        {/* Color picker */}
        <div>
          <p className="text-xs text-muted-foreground mb-2">Task color</p>
          <div className="flex gap-2 flex-wrap">
            {COLORS.map(({ label, value }) => (
              <button
                key={label}
                type="button"
                title={label}
                onClick={() => setColor(value)}
                className="w-5 h-5 rounded-full border-2 transition-transform hover:scale-110"
                style={{
                  backgroundColor: value ?? '#374151',
                  borderColor: color === value ? 'white' : 'transparent'
                }}
              />
            ))}
          </div>
        </div>

        <div className="flex gap-2 justify-end pt-1">
          <button
            type="button"
            onClick={onClose}
            className="px-3 py-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={saving || !title.trim()}
            className="px-4 py-1.5 text-sm bg-primary text-primary-foreground rounded hover:opacity-90 disabled:opacity-50 transition-opacity"
          >
            {saving ? 'Saving…' : initial ? 'Save changes' : 'Add task'}
          </button>
        </div>
      </form>
    </div>
  )
}

import { useEffect, useState, useRef } from 'react'
import { useSubtasks } from '@renderer/hooks/useSubtasks'
import { CheckSquare, Square, Trash2, Plus } from 'lucide-react'

interface SubtaskListProps {
  taskId: number
}

export function SubtaskList({ taskId }: SubtaskListProps) {
  const { subtasks, refresh, add, toggle, remove } = useSubtasks(taskId)
  const [newTitle, setNewTitle] = useState('')
  const inputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    refresh()
  }, [taskId])

  const handleAdd = async () => {
    const title = newTitle.trim()
    if (!title) return
    await add(title)
    setNewTitle('')
    inputRef.current?.focus()
  }

  return (
    <div className="ml-4 mt-2 space-y-1">
      {subtasks.map((s) => (
        <div key={s.id} className="flex items-center gap-2 group">
          <button
            onClick={() => toggle(s.id, !s.isComplete)}
            className="flex-shrink-0 text-muted-foreground hover:text-primary transition-colors"
          >
            {s.isComplete ? (
              <CheckSquare className="h-3.5 w-3.5 text-primary" />
            ) : (
              <Square className="h-3.5 w-3.5" />
            )}
          </button>
          <span
            className={`flex-1 text-xs ${s.isComplete ? 'line-through text-muted-foreground' : 'text-foreground'}`}
          >
            {s.title}
          </span>
          <button
            onClick={() => remove(s.id)}
            className="opacity-0 group-hover:opacity-100 p-0.5 text-muted-foreground hover:text-destructive transition-all"
          >
            <Trash2 className="h-3 w-3" />
          </button>
        </div>
      ))}

      {/* Inline add */}
      <div className="flex items-center gap-2">
        <Plus className="h-3.5 w-3.5 text-muted-foreground flex-shrink-0" />
        <input
          ref={inputRef}
          type="text"
          placeholder="Add subtask…"
          value={newTitle}
          onChange={(e) => setNewTitle(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') handleAdd()
          }}
          className="flex-1 bg-transparent text-xs text-foreground placeholder:text-muted-foreground focus:outline-none"
        />
      </div>
    </div>
  )
}

import { useState, useCallback } from 'react'
import type { Task, CreateTaskPayload, UpdateTaskPayload, CompleteTaskResult } from '@shared/types'
import * as ipc from '@renderer/lib/ipc'
import { arrayMove } from '@dnd-kit/sortable'

export function useTasks(opts?: { categoryId?: number; includeComplete?: boolean }) {
  const [tasks, setTasks] = useState<Task[]>([])
  const [loading, setLoading] = useState(false)

  const refresh = useCallback(async () => {
    setLoading(true)
    try {
      setTasks(await ipc.getAllTasks(opts))
    } finally {
      setLoading(false)
    }
  }, [opts?.categoryId, opts?.includeComplete])

  const addTask = useCallback(async (payload: CreateTaskPayload) => {
    const newTask = await ipc.createTask(payload)
    setTasks((prev) => [...prev, newTask])
    return newTask
  }, [])

  const editTask = useCallback(async (payload: UpdateTaskPayload) => {
    const updated = await ipc.updateTask(payload)
    setTasks((prev) => prev.map((t) => (t.id === updated.id ? updated : t)))
    return updated
  }, [])

  const removeTask = useCallback(async (id: number) => {
    await ipc.deleteTask(id)
    setTasks((prev) => prev.filter((t) => t.id !== id))
  }, [])

  /**
   * Optimistically reorder tasks by dragging.
   * oldIndex/newIndex are positions in the current `tasks` array.
   */
  const reorder = useCallback(
    async (oldIndex: number, newIndex: number) => {
      const reordered = arrayMove(tasks, oldIndex, newIndex)
      setTasks(reordered) // optimistic update
      try {
        await ipc.reorderTasks(reordered.map((t) => t.id))
      } catch {
        // Revert on failure
        setTasks(tasks)
      }
    },
    [tasks]
  )

  const markComplete = useCallback(async (id: number): Promise<CompleteTaskResult> => {
    const result = await ipc.completeTask(id)
    setTasks((prev) => prev.filter((t) => t.id !== id))
    return result
  }, [])

  return { tasks, loading, refresh, addTask, editTask, removeTask, reorder, markComplete }
}

import { useState, useCallback } from 'react'
import type { Subtask } from '@shared/types'
import * as ipc from '@renderer/lib/ipc'

export function useSubtasks(taskId: number) {
  const [subtasks, setSubtasks] = useState<Subtask[]>([])

  const refresh = useCallback(async () => {
    setSubtasks(await ipc.getSubtasksByTask(taskId))
  }, [taskId])

  const add = useCallback(
    async (title: string) => {
      const s = await ipc.createSubtask({ taskId, title })
      setSubtasks((prev) => [...prev, s])
    },
    [taskId]
  )

  const toggle = useCallback(async (id: number, isComplete: boolean) => {
    const updated = await ipc.updateSubtask({ id, isComplete })
    setSubtasks((prev) => prev.map((s) => (s.id === id ? updated : s)))
  }, [])

  const remove = useCallback(async (id: number) => {
    await ipc.deleteSubtask(id)
    setSubtasks((prev) => prev.filter((s) => s.id !== id))
  }, [])

  return { subtasks, refresh, add, toggle, remove }
}

