  return rows.map(rowToSubtask)
}

export function createSubtask(db: Database.Database, payload: CreateSubtaskPayload): Subtask {
  const maxOrder = (
    db
      .prepare('SELECT MAX(sort_order) AS m FROM subtasks WHERE task_id = ?')
      .get(payload.taskId) as { m: number | null }
  ).m
  const sortOrder = maxOrder != null ? maxOrder + 1 : 0

  const result = db
    .prepare('INSERT INTO subtasks (task_id, title, sort_order) VALUES (?, ?, ?)')
    .run(payload.taskId, payload.title, sortOrder)

  const row = db
    .prepare('SELECT * FROM subtasks WHERE id = ?')
    .get(result.lastInsertRowid) as Record<string, unknown>
  return rowToSubtask(row)
}

