import { ipcMain } from 'electron'
import { IPC } from '@shared/ipc-channels'
import type { CreateTaskPayload, UpdateTaskPayload } from '@shared/types'
import { getDb } from '../db'
import * as db from '../db/tasks'
import { addXp, getStats, getTodayPomodoroCount } from '../db/gamification'

export function registerTaskHandlers(): void {
  ipcMain.handle(IPC.TASKS.GET_ALL, (_e, opts) => db.getAllTasks(getDb(), opts))
  ipcMain.handle(IPC.TASKS.GET_BY_ID, (_e, { id }) => db.getTaskById(getDb(), id))
  ipcMain.handle(IPC.TASKS.CREATE, (_e, payload: CreateTaskPayload) =>
    db.createTask(getDb(), payload)
  )
  ipcMain.handle(IPC.TASKS.UPDATE, (_e, payload: UpdateTaskPayload) =>
    db.updateTask(getDb(), payload)
  )
  ipcMain.handle(IPC.TASKS.DELETE, (_e, { id }) => db.deleteTask(getDb(), id))
  ipcMain.handle(IPC.TASKS.REORDER, (_e, { orderedIds }) => db.reorderTasks(getDb(), orderedIds))
  ipcMain.handle(IPC.TASKS.COMPLETE, (_e, { id }) => {
    const database = getDb()
    const task = db.completeTask(database, id)
    const xpGained = task.xpValue
    const stats = addXp(database, xpGained)
    const todayPomodoros = getTodayPomodoroCount(database)
    return { task, xpGained, stats: { ...stats, todayPomodoros } }
  })
}

import { contextBridge, ipcRenderer } from 'electron'
import { IPC } from '@shared/ipc-channels'

// Expose a whitelist of invoke calls to the renderer via window.electron.
// This keeps contextIsolation intact — the renderer never touches Node APIs directly.
const api = {
  invoke: (channel: string, ...args: unknown[]) => {
    // Only allow channels defined in our IPC constants
    const allowed = Object.values(IPC).flatMap((group) => Object.values(group))
    if (!allowed.includes(channel)) {
      throw new Error(`IPC channel not allowed: ${channel}`)
    }
    return ipcRenderer.invoke(channel, ...args)
  }
}

contextBridge.exposeInMainWorld('electron', { ipcRenderer: api })

// TypeScript declaration for window.electron in the renderer
export type ElectronApi = typeof api

