import { useEffect, useRef, useState } from 'react'
import { useAppStore } from '@renderer/store/appStore'
import type { CreateTaskPayload, CategoryWithCount } from '@shared/types'
import { Zap, X } from 'lucide-react'

interface BrainDumpInputProps {
  categories: CategoryWithCount[]
  onAdd: (payload: CreateTaskPayload) => Promise<void>
}

export function BrainDumpInput({ categories, onAdd }: BrainDumpInputProps) {
  const { brainDumpOpen, closeBrainDump, toggleBrainDump, activeCategoryId } = useAppStore()
  const [value, setValue] = useState('')
  const [adding, setAdding] = useState(false)
  const inputRef = useRef<HTMLInputElement>(null)

  // Ctrl+Space global shortcut
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.code === 'Space') {
        e.preventDefault()
        toggleBrainDump()
      }
      if (e.key === 'Escape' && brainDumpOpen) {
        closeBrainDump()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [brainDumpOpen, toggleBrainDump, closeBrainDump])

  // Focus input when opened
  useEffect(() => {
    if (brainDumpOpen) {
      setTimeout(() => inputRef.current?.focus(), 50)
    }
  }, [brainDumpOpen])

  const handleAdd = async () => {
    const title = value.trim()
    if (!title || adding) return

    // Default to active category, fallback to first category (Inbox)
    const categoryId = activeCategoryId ?? categories[0]?.id ?? null

    setAdding(true)
    try {
      await onAdd({
        title,
        categoryId,
        color: null,
        dueDate: null,
        dueBefore5pm: false,
        timeEstimateMins: null,
        sortOrder: 0,
        isComplete: false,
        recurringPattern: 'none',
        recurringBaseId: null
      })
      setValue('') // stay open for rapid-fire entries
      inputRef.current?.focus()
    } finally {
      setAdding(false)
    }
  }

  if (!brainDumpOpen) return null

  return (
    <div className="flex-shrink-0 border-b border-border bg-card/80 px-4 py-3 flex items-center gap-3">
      <Zap className="h-4 w-4 text-primary flex-shrink-0" />
      <input
        ref={inputRef}
        type="text"
        placeholder="Brain dump — type a task and hit Enter. Escape to close."
        value={value}
        onChange={(e) => setValue(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === 'Enter') handleAdd()
        }}
        className="flex-1 bg-transparent text-sm text-foreground placeholder:text-muted-foreground focus:outline-none"
      />
      {adding && (
        <span className="text-xs text-muted-foreground">Adding…</span>
      )}
      <button
        onClick={closeBrainDump}
        className="p-1 text-muted-foreground hover:text-foreground transition-colors"
      >
        <X className="h-4 w-4" />
      </button>
    </div>
  )
}

import { useState } from 'react'
import type { CategoryWithCount, CreateCategoryPayload, UpdateCategoryPayload } from '@shared/types'
import { CategoryForm } from './CategoryForm'
import { Pencil, Trash2 } from 'lucide-react'
import { cn } from '@renderer/lib/utils'

interface CategoryItemProps {
  category: CategoryWithCount
  isActive: boolean
  onSelect: () => void
  onEdit: (payload: UpdateCategoryPayload) => Promise<void>
  onDelete: (id: number) => Promise<void>
}

export function CategoryItem({ category, isActive, onSelect, onEdit, onDelete }: CategoryItemProps) {
  const [showForm, setShowForm] = useState(false)
  const [hovered, setHovered] = useState(false)

  return (
    <>
      <div
        className={cn(
          'group flex items-center gap-2 px-3 py-2 rounded-md cursor-pointer transition-colors',
          isActive ? 'bg-accent text-foreground' : 'text-muted-foreground hover:bg-accent/50 hover:text-foreground'
        )}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
        onClick={onSelect}
      >
        {/* Category color dot */}
        <span
          className="w-2.5 h-2.5 rounded-full flex-shrink-0"
          style={{ backgroundColor: category.color }}
        />

        <span className="flex-1 text-sm truncate">{category.name}</span>

        {/* Task count badge */}
        {category.taskCount > 0 && (
          <span className="text-xs bg-muted text-muted-foreground rounded-full px-1.5 py-0.5 font-mono">
            {category.taskCount}
          </span>
        )}

        {/* Action buttons — only shown on hover */}
        {hovered && (
          <div className="flex gap-0.5 ml-1" onClick={(e) => e.stopPropagation()}>
            <button
              onClick={() => setShowForm(true)}
              className="p-1 rounded hover:bg-muted text-muted-foreground hover:text-foreground transition-colors"
            >
              <Pencil className="h-3 w-3" />
            </button>
            <button
              onClick={() => onDelete(category.id)}
              className="p-1 rounded hover:bg-muted text-muted-foreground hover:text-destructive transition-colors"
            >
              <Trash2 className="h-3 w-3" />
            </button>
          </div>
        )}
      </div>

      {showForm && (
        <CategoryForm
          initial={category}
          onSave={onEdit}
          onClose={() => setShowForm(false)}
        />
      )}
    </>
  )
}

import { useState, useEffect, useCallback, useRef } from 'react'
import * as ipc from '@renderer/lib/ipc'

// Pomodoro cycle: 4 work sessions of 25min, each followed by a 5min break,
// with a 30min long break after the 4th session.
const WORK_S = 25 * 60
const SHORT_BREAK_S = 5 * 60
const LONG_BREAK_S = 30 * 60

type Phase = 'idle' | 'work' | 'short_break' | 'long_break'

export interface PomodoroState {
  phase: Phase
  sessionIndex: number  // 0–3, which of the 4 work sessions we're on
  remainingS: number
  totalS: number        // total seconds for the current phase (for progress calc)
  isRunning: boolean
  completedSessions: number // work sessions completed this cycle
}

export interface PomodoroControls {
  start: (taskId?: number) => void
  stop: () => void
  reset: () => void
}

export function usePomodoro(): [PomodoroState, PomodoroControls] {
  const [state, setState] = useState<PomodoroState>({
    phase: 'idle',
    sessionIndex: 0,
    remainingS: WORK_S,
    totalS: WORK_S,
    isRunning: false,
    completedSessions: 0
  })

  const sessionIdRef = useRef<number | null>(null)
  const taskIdRef = useRef<number | undefined>(undefined)

  // Advance to the next phase when a session ends
  const advance = useCallback((prevState: PomodoroState) => {
    if (sessionIdRef.current !== null) {
      ipc.completePomodoroSession(sessionIdRef.current).catch(() => {})
      sessionIdRef.current = null
    }

    const nextSessionIndex = prevState.sessionIndex
    const nextCompleted = prevState.completedSessions + (prevState.phase === 'work' ? 1 : 0)

    let nextPhase: Phase
    let nextTotal: number

    if (prevState.phase === 'work') {
      if (nextCompleted % 4 === 0) {
        // After 4th work session → long break, reset cycle
        nextPhase = 'long_break'
        nextTotal = LONG_BREAK_S
      } else {
        nextPhase = 'short_break'
        nextTotal = SHORT_BREAK_S
      }
    } else {
      // After a break → next work session
      nextPhase = 'work'
      nextTotal = WORK_S
    }

    const newSessionIndex = nextPhase === 'work' ? nextCompleted % 4 : prevState.sessionIndex

    // Log the next session start
    const phase = nextPhase === 'work' ? 'work' : nextPhase === 'short_break' ? 'short_break' : 'long_break'
    ipc
      .startPomodoroSession({ taskId: taskIdRef.current, phase, durationS: nextTotal })
      .then(({ sessionId }) => {
        sessionIdRef.current = sessionId
      })
      .catch(() => {})

    return {
      phase: nextPhase,
      sessionIndex: newSessionIndex,
      remainingS: nextTotal,
      totalS: nextTotal,
      isRunning: true, // auto-start next phase
      completedSessions: nextCompleted
    }
  }, [])

  // Tick the timer every second when running
  useEffect(() => {
    if (!state.isRunning) return

    const id = setInterval(() => {
      setState((prev) => {
        if (prev.remainingS <= 1) {
          return advance(prev)
        }
        return { ...prev, remainingS: prev.remainingS - 1 }
      })
    }, 1000)

    return () => clearInterval(id)
  }, [state.isRunning, advance])

  const start = useCallback((taskId?: number) => {
    taskIdRef.current = taskId
    setState((prev) => {
      const phase = prev.phase === 'idle' ? 'work' : prev.phase
      const total = phase === 'work' ? WORK_S : phase === 'short_break' ? SHORT_BREAK_S : LONG_BREAK_S
      const remaining = prev.phase === 'idle' ? WORK_S : prev.remainingS

      ipc
        .startPomodoroSession({
          taskId,
          phase: phase as 'work' | 'short_break' | 'long_break',
          durationS: total
        })
        .then(({ sessionId }) => {
          sessionIdRef.current = sessionId
        })
        .catch(() => {})

      return { ...prev, phase, totalS: total, remainingS: remaining, isRunning: true }
    })
  }, [])

  const stop = useCallback(() => {
    setState((prev) => ({ ...prev, isRunning: false }))
  }, [])

  const reset = useCallback(() => {
    sessionIdRef.current = null
    taskIdRef.current = undefined
    setState({
      phase: 'idle',
      sessionIndex: 0,
      remainingS: WORK_S,
      totalS: WORK_S,
      isRunning: false,
      completedSessions: 0
    })
  }, [])

  return [state, { start, stop, reset }]
}

import { useState } from 'react'
import type { CategoryWithCount, CreateCategoryPayload, UpdateCategoryPayload } from '@shared/types'

const PRESET_COLORS = [
  '#6366f1', '#8b5cf6', '#ec4899', '#ef4444',
  '#f97316', '#eab308', '#22c55e', '#14b8a6',
  '#3b82f6', '#06b6d4', '#a3e635', '#f43f5e'
]

interface CategoryFormProps {
  initial?: CategoryWithCount
  onSave: (payload: CreateCategoryPayload | UpdateCategoryPayload) => Promise<void>
  onClose: () => void
}

export function CategoryForm({ initial, onSave, onClose }: CategoryFormProps) {
  const [name, setName] = useState(initial?.name ?? '')
  const [color, setColor] = useState(initial?.color ?? PRESET_COLORS[0])
  const [saving, setSaving] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!name.trim()) return
    setSaving(true)
    try {
      if (initial) {
        await onSave({ id: initial.id, name: name.trim(), color })
      } else {
        await onSave({ name: name.trim(), color })
      }
      onClose()
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60">
      <form
        onSubmit={handleSubmit}
        className="bg-card border border-border rounded-lg p-5 w-80 shadow-xl"
      >
        <h2 className="font-semibold text-foreground mb-4">
          {initial ? 'Edit Category' : 'New Category'}
        </h2>

        <input
          autoFocus
          type="text"
          placeholder="Category name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="w-full bg-input border border-border rounded px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-1 focus:ring-ring mb-4"
        />

        <p className="text-xs text-muted-foreground mb-2">Color</p>
        <div className="flex flex-wrap gap-2 mb-5">
          {PRESET_COLORS.map((c) => (
            <button
              key={c}
              type="button"
              onClick={() => setColor(c)}
              className="w-6 h-6 rounded-full border-2 transition-transform hover:scale-110"
              style={{
                backgroundColor: c,
                borderColor: color === c ? 'white' : 'transparent'
              }}
            />
          ))}
        </div>

        <div className="flex gap-2 justify-end">
          <button
            type="button"
            onClick={onClose}
            className="px-3 py-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={saving || !name.trim()}
            className="px-4 py-1.5 text-sm bg-primary text-primary-foreground rounded hover:opacity-90 disabled:opacity-50 transition-opacity"
          >
            {saving ? 'Saving…' : 'Save'}
          </button>
