// All IPC channel name constants. Import in both main handlers and renderer wrappers
// to avoid string typos — the type system will catch mismatches.

export const IPC = {
  TASKS: {
    GET_ALL: 'tasks:get-all',
    GET_BY_ID: 'tasks:get-by-id',
    CREATE: 'tasks:create',
    UPDATE: 'tasks:update',
    DELETE: 'tasks:delete',
    REORDER: 'tasks:reorder',
    COMPLETE: 'tasks:complete'
  },
  CATEGORIES: {
    GET_ALL: 'categories:get-all',
    CREATE: 'categories:create',
    UPDATE: 'categories:update',
    DELETE: 'categories:delete'
  },
  SUBTASKS: {
    GET_BY_TASK: 'subtasks:get-by-task',
    CREATE: 'subtasks:create',
    UPDATE: 'subtasks:update',
    DELETE: 'subtasks:delete',
    REORDER: 'subtasks:reorder'
  },
  POMODORO: {
    START_SESSION: 'pomodoro:start-session',
    COMPLETE_SESSION: 'pomodoro:complete-session'
  },
  APP: {
    MINIMIZE_TO_TRAY: 'app:minimize-to-tray',
    QUIT: 'app:quit'
  },
  GAMIFICATION: {
    GET_STATS: 'gamification:get-stats'
  }
} as const

import { ipcMain, BrowserWindow } from 'electron'
import { IPC } from '@shared/ipc-channels'
import { registerTaskHandlers } from './tasks'
import { registerCategoryHandlers } from './categories'
import { registerSubtaskHandlers } from './subtasks'
import { registerPomodoroHandlers } from './pomodoro'
import { registerGamificationHandlers } from './gamification'

export function registerAllHandlers(mainWindow: BrowserWindow): void {
  registerTaskHandlers()
  registerCategoryHandlers()
  registerSubtaskHandlers()
  registerPomodoroHandlers()
  registerGamificationHandlers()

  ipcMain.handle(IPC.APP.MINIMIZE_TO_TRAY, () => {
    mainWindow.hide()
  })

  ipcMain.handle(IPC.APP.QUIT, () => {
    mainWindow.destroy()
  })
}

