import { useAppStore } from '@renderer/store/appStore'
import { PomodoroTimer } from './PomodoroTimer'
import { SubtaskList } from '@renderer/components/tasks/SubtaskList'
import type { Task, CategoryWithCount } from '@shared/types'
import { X, Clock, CheckSquare } from 'lucide-react'
import { formatMinutes } from '@renderer/lib/utils'

interface FocusModeProps {
  activeTasks: Task[]
  categories: CategoryWithCount[]
  onComplete: (id: number) => Promise<void>
}

export function FocusMode({ activeTasks, categories, onComplete }: FocusModeProps) {
  const { focusMode, focusTaskId, exitFocusMode, enterFocusMode } = useAppStore()

  if (!focusMode) return null

  const task = activeTasks.find((t) => t.id === focusTaskId)
  const category = task ? categories.find((c) => c.id === task.categoryId) : undefined

  const handleComplete = async () => {
    if (!task) return
    await onComplete(task.id)
    // Find the next task (first in list that isn't the one we just completed)
    const next = activeTasks.find((t) => t.id !== task.id)
    if (next) {
      enterFocusMode(next.id)
    } else {
      exitFocusMode()
    }
  }

  return (
    <div className="fixed inset-0 z-50 bg-background flex flex-col">
      {/* Top bar */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-border">
        <p className="text-xs font-semibold uppercase tracking-widest text-muted-foreground">
          Focus Mode
        </p>
        <button
          onClick={exitFocusMode}
          className="p-1.5 rounded text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
          title="Exit focus mode"
        >
          <X className="h-5 w-5" />
        </button>
      </div>

      {/* Content */}
      <div className="flex-1 flex flex-col items-center justify-center gap-6 px-8 overflow-y-auto py-8">
        {task ? (
          <>
            {/* Task info */}
            <div className="text-center max-w-xl w-full">
              {category && (
                <div className="flex items-center justify-center gap-1.5 mb-3">
                  <span
                    className="w-2 h-2 rounded-full"
                    style={{ backgroundColor: category.color }}
                  />
                  <span className="text-xs text-muted-foreground">{category.name}</span>
                </div>
              )}
              <h1 className="text-3xl font-bold text-foreground leading-tight">{task.title}</h1>
              {task.description && (
                <p className="mt-3 text-sm text-muted-foreground leading-relaxed whitespace-pre-wrap">
                  {task.description}
                </p>
              )}
              {task.timeEstimateMins != null && (
                <p className="flex items-center justify-center gap-1.5 mt-3 text-sm text-muted-foreground">
                  <Clock className="h-4 w-4" />
                  Estimated {formatMinutes(task.timeEstimateMins)}
                </p>
              )}
            </div>

            {/* Subtasks */}
            <div className="w-full max-w-sm bg-card border border-border rounded-lg px-4 py-3">
              <p className="text-xs font-semibold uppercase tracking-wider text-muted-foreground mb-1">
                Subtasks
              </p>
              <SubtaskList taskId={task.id} />
            </div>

            {/* Pomodoro timer */}
            <div className="bg-card border border-border rounded-xl px-12 py-2">
              <PomodoroTimer taskId={task.id} />
            </div>

            {/* Complete task */}
            <button
              onClick={handleComplete}
              className="flex items-center gap-2 px-5 py-2 rounded-full text-sm font-semibold bg-primary text-primary-foreground hover:opacity-90 transition-opacity"
            >
              <CheckSquare className="h-4 w-4" />
              Mark task complete
            </button>
          </>
        ) : (
          <p className="text-muted-foreground text-lg">No task selected.</p>
        )}
      </div>

      <p className="text-center text-xs text-muted-foreground pb-4">
        Press Escape or click ✕ to exit focus mode
      </p>
    </div>
  )
}

